const t=document.createElement("script");t.src=chrome.runtime.getURL("inpage.js");t.onload=()=>t.remove();(document.head||document.documentElement).appendChild(t);window.addEventListener("message",async n=>{var a;if(n.source!==window||((a=n.data)==null?void 0:a.type)!=="SOLEN_REQUEST")return;const{id:s,method:o,params:i}=n.data,r=window.location.origin;try{let e;switch(o){case"connect":e=await chrome.runtime.sendMessage({type:"DAPP_CONNECT",origin:r});break;case"getAccounts":e=await chrome.runtime.sendMessage({type:"DAPP_GET_ACCOUNTS",origin:r});break;case"signAndSubmit":e=await chrome.runtime.sendMessage({type:"DAPP_SIGN_AND_SUBMIT",origin:r,operation:i});break;default:e={error:`Unknown method: ${o}`}}window.postMessage({type:"SOLEN_RESPONSE",id:s,result:e},"*")}catch(e){window.postMessage({type:"SOLEN_RESPONSE",id:s,error:e instanceof Error?e.message:"Extension error"},"*")}});
